    const MOD = 10**9 + 7;
    const freq = new Map<number, number>();

    for (const [x, y] of points) {
        if (!freq.has(y)) {
            freq.set(y, 0);
        }
        freq.set(y, freq.get(y)! + 1);
    }

    let S = 0;
    let T = 0;
    const inv2 = 500000004; // Modular inverse of 2 modulo 1e9+7

    for (const count of freq.values()) {
        const term = (count * (count - 1)) / 2;
        S = (S + term) % MOD;
        T = (T + term * term) % MOD;
    }

    const temp = (S * S - T) % MOD;
    if (temp < 0) {
        temp += MOD;
    }

    const ans = (temp * inv2) % MOD;
    return ans;
}
```

